#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        char board[N][M];
        for (int i = 0; i < N; i++) {
            scanf("%s", board[i]);
        }
        int CW[min(N, M)], CB[min(N, M)];
        for (int i = 0; i < min(N, M); i++) {
            scanf("%d", &CW[i]);
        }
        for (int i = 0; i < min(N, M); i++) {
            scanf("%d", &CB[i]);
        }
        // calculate the maximum achievable cost
        int maxCost = 0;
        for (int k = 1; k <= min(N, M); k++) {
            int whiteCount = 0, blackCount = 0;
            for (int i = 0; i <= N - k; i++) {
                for (int j = 0; j <= M - k; j++) {
                    int white = 0, black = 0;
                    for (int x = 0; x < k; x++) {
                        for (int y = 0; y < k; y++) {
                            if (board[i + x][j + y] == '0') {
                                white++;
                            } else if (board[i + x][j + y] == '1') {
                                black++;
                            }
                        }
                    }
                    if (white == k * k) {
                        whiteCount++;
                    }
                    if (black == k * k) {
                        blackCount++;
                    }
                }
            }
            maxCost += CW[k - 1] * whiteCount + CB[k - 1] * blackCount;
        }
        printf("%d\n", maxCost);
    }
    return 0;
}

